  ('heelevel3-722caeab-moex-00017', 'heelevel3-722caeab', 'heelevel3-722caeab-moex-113-80dca3d6', 'sub-heelevel3-722caeab-02', NULL, 'essay', '2024年即將於法國巴黎舉行第 33屆夏季奧林匹克運動會（簡稱奧運）。
奧運不只是一個全球矚目的國際體育競賽活動，也是一個重要的國際傳
播場域。請申論奧運如何牽涉到國際傳播的多個文化與媒體面向，有什
麼理論概念可以幫助我們描述、詮釋和討論？在上述的一般申論基礎上，
最後請特別申論臺灣在奧運相關國際傳播現象中的特殊性。（25分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:33:18+00:00", "source_pdf_sha1": "0792cf2ec0a9", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "314", "s": "0312", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "國際傳播與國際現勢", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "civil_slug": "heelevel3", "civil_category": "新聞(選試英文)"}'::jsonb, NULL)
